// Extrair e normalizar dados do payload do Typebot
const body = $input.first().json.body || $input.first().json;

const nome      = (body.nome      || 'Desconhecido').trim();
const whatsapp  = (body.whatsapp  || '').replace(/\D/g, '');
const bairro    = body.bairro    || '';
const familia   = body.familia   || '';
const usa_sus   = body.usa_sus   || '';
const maior_dor = body.maior_dor || '';
const interesse = (body.interesse || '').toLowerCase();
const origem    = body.origem    || 'typebot-qualificacao-bp';
const timestamp = body.timestamp || new Date().toISOString();

// CLASSIFICAÇÃO DO LEAD
// Quente: quer falar com consultor (interesse=sim) e tem WhatsApp
// Morno:  respondeu tudo mas não quer agora
// Frio:   não tem WhatsApp (saiu antes da captura)
let score = 'frio';
if (interesse === 'sim' && whatsapp.length >= 10) {
  score = 'quente';
} else if (bairro && familia && usa_sus && maior_dor) {
  score = 'morno';
}

// Montar resumo para o Closer
const familiaLabel = {
  'Só eu (1 pessoa)': '1 pessoa',
  '2 a 4 pessoas':    '2–4 pessoas',
  '5 ou mais pessoas':'5+ pessoas'
}[familia] || familia;

const susLabel = {
  'Sim, com frequência': 'usa SUS sempre',
  'Às vezes':            'usa SUS às vezes',
  'Raramente / não preciso': 'quase não usa SUS'
}[usa_sus] || usa_sus;

console.log(`Lead novo: ${nome} | Score: ${score} | WA: ${whatsapp}`);

return [{ json: {
  nome, whatsapp, bairro, familia: familiaLabel,
  usa_sus: susLabel, maior_dor, interesse, score,
  origem, timestamp
} }];

// Montar mensagem de alerta para o Closer via WhatsApp
const lead = $('Normalizar Dados + Classificar Lead').first().json;
const conversa = $input.first().json;
const conversaId = conversa.id || '???';
const conversaUrl = `${$env.CHATWOOT_URL}/app/accounts/${$env.CHATWOOT_ACCOUNT_ID}/conversations/${conversaId}`;

const mensagem =
  `🔥 *LEAD QUENTE — Bairro da Paz*\n\n` +
  `👤 *Nome:* ${lead.nome}\n` +
  `📱 *WhatsApp:* ${lead.whatsapp}\n` +
  `📍 *Bairro:* ${lead.bairro}\n` +
  `👨‍👩‍👧 *Família:* ${lead.familia}\n` +
  `🏥 *SUS:* ${lead.usa_sus}\n` +
  `😤 *Maior dor:* ${lead.maior_dor}\n\n` +
  `✅ *Quer falar com consultor agora!*\n\n` +
  `💬 Chatwoot: ${conversaUrl}\n\n` +
  `⚡ Entrar em contato em até *30 minutos*.`;

return [{ json: { mensagem, lead, conversaId } }];

// Lead morno: respondeu tudo mas não quer falar agora
// Estratégia: cadência leve D+1 / D+3 / D+7 via WhatsApp
const lead = $input.first().json;

const msg_d1 =
  `Oi${lead.nome !== 'Desconhecido' ? ', ' + lead.nome : ''}! Aqui é a equipe da SST Clínica Bairro da Paz 😊\n\n` +
  `Vi que você se interessou pelo SST Card mas talvez não fosse o momento certo.\n\n` +
  `Só queria te lembrar: por R$39,90/mês você e mais 3 da família têm consultas, laboratório e telemedicina — sem fila, sem burocracia.\n\n` +
  `Se quiser saber mais, é só responder aqui!`;

return [{ json: {
  ...lead,
  mensagem_d1: msg_d1,
  data_d1: new Date(Date.now() + 86400000).toISOString().split('T')[0],
  data_d3: new Date(Date.now() + 3 * 86400000).toISOString().split('T')[0],
  data_d7: new Date(Date.now() + 7 * 86400000).toISOString().split('T')[0]
} }];

// Montar alerta mais suave para o Closer (lead morno)
const lead = $input.first().json;

const mensagem =
  `🟡 *Lead Morno — Bairro da Paz*\n\n` +
  `👤 *Nome:* ${lead.nome}\n` +
  `📍 *Bairro:* ${lead.bairro}\n` +
  `👨‍👩‍👧 *Família:* ${lead.familia}\n` +
  `😤 *Maior dor:* ${lead.maior_dor}\n\n` +
  `⚠️ Não quer contato agora. Cadência D+1/D+3/D+7 iniciada automaticamente.\n\n` +
  `💡 Se quiser antecipar o contato, WhatsApp: ${lead.whatsapp || 'não informado'}`;

return [{ json: { ...lead, mensagem } }];

// Registrar lead quente no Sheets também (histórico + comissão)
const lead = $('Normalizar Dados + Classificar Lead').first().json;
const chatwoot = $input.first().json;

return [{ json: {
  ...lead,
  chatwoot_conversa_id: chatwoot.id || '',
  data_entrada: new Date().toISOString().split('T')[0],
  status: 'alerta-enviado'
} }];
